VALUES
  ('judicial-57f41407-moex-00453', 'judicial-57f41407', 'judicial-57f41407-moex-112-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '甲以乙為被告，向A地方法院起訴，依買賣關係請求乙給付價金；嗣甲發覺第一審管轄權應為B地 方法院，乃立即向B法院提起同一之訴。A、B法院均未辯論終結，下列敘述何者正確？', '["A法院應為不受理判決", "A法院應裁定駁回甲之起訴", "B法院應裁定駁回甲之起訴", "B法院應為本案判決"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:39+00:00", "source_pdf_sha1": "3d06ebd3dac6", "answer_pdf_sha1": "a08edc8cf0cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "301", "s": "0409", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00454', 'judicial-57f41407', 'judicial-57f41407-moex-112-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '下列何種情形，證人不得拒絕證言？', '["證人為一造當事人四親等之旁系血親", "證人就其業務上有秘密義務之事項受訊問", "證人為一造當事人四親等之旁系姻親", "證人為一造當事人之未婚配偶"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:39+00:00", "source_pdf_sha1": "3d06ebd3dac6", "answer_pdf_sha1": "a08edc8cf0cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "301", "s": "0409", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00455', 'judicial-57f41407', 'judicial-57f41407-moex-112-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '關於文書形式證據力，下列敘述何者正確？', '["文書依其程式及意旨得認作本國公文書者，不推定真正", "私文書經公證人認證者，推定其真正", "私文書經本人簽名者，不推定真正", "當事人就私文書之本人蓋章為不知陳述時，一律推定該文書不真正"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:39+00:00", "source_pdf_sha1": "3d06ebd3dac6", "answer_pdf_sha1": "a08edc8cf0cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "301", "s": "0409", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00456', 'judicial-57f41407', 'judicial-57f41407-moex-112-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '關於起訴前應經法院調解之事件，下列敘述何者正確？', '["主任調解委員認調解之聲請為依據信用卡契約有所請求者，應報請司法事務官許可後，逕以裁定駁回", "因定不動產之界線發生爭執，且該不動產價值未逾新臺幣500萬元，又當事人間有四親等內直系血 親或旁系血親之關係者，於起訴前，應經法院依職權指派地政士為主任調解委員，進行調解", "法院認調解之聲請，為經其他法定調解機關調解未成立者，得逕以裁定駁回之", "調解委員認調解之聲請為調解顯無成立之望者，應報請司法事務官許可後，逕以裁定駁回"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:39+00:00", "source_pdf_sha1": "3d06ebd3dac6", "answer_pdf_sha1": "a08edc8cf0cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "301", "s": "0409", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00457', 'judicial-57f41407', 'judicial-57f41407-moex-112-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '被告抗辯不適用簡易訴訟程序，下列何者為有理由？', '["兩造簽訂書面買賣契約，約定因該契約所生爭議應適用簡易訴訟程序，原告主張被告未依該契約履 行債務，請求被告給付新臺幣（下同）300萬元", "被告向原告借款36萬元未依約清償，原告訴請被告返還借款本息", "原告依票據法律關係，起訴請求被告給付票款100萬元，嗣追加依委任關係，請求被告償還處理委 任事務所支出之費用62萬元", "原告主張被告未履行股權移轉契約之債務，訴請被告移轉市價78萬元之甲公司股份10萬股，經簡 易庭法官適用簡易訴訟程序定期言詞辯論，被告曾無異議而為本案言詞辯論"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:39+00:00", "source_pdf_sha1": "3d06ebd3dac6", "answer_pdf_sha1": "a08edc8cf0cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "301", "s": "0409", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00458', 'judicial-57f41407', 'judicial-57f41407-moex-112-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '下列何者為小額訴訟程序第一審判決必須記載之事項？', '["確定訴訟費用額", "事實", "理由之要領", "當事人所用之證據"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:39+00:00", "source_pdf_sha1": "3d06ebd3dac6", "answer_pdf_sha1": "a08edc8cf0cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "301", "s": "0409", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00459', 'judicial-57f41407', 'judicial-57f41407-moex-112-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '甲主張乙及丙各自無權占用伊所有之系爭土地，依所有物返還請求權及不當得利返還請求權，分別請求 乙及丙返還系爭土地，及各至返還系爭土地之日止，按日給付新臺幣（下同）1萬元之相當於租金之不 當得利。第一審判決乙應返還系爭土地，及至返還系爭土地之日止，按日給付5,000元，另駁回甲其餘 請求。乙就其敗訴部分不服，提起上訴。甲於上訴期間內，未聲明不服。關於第二審附帶上訴，下列敘 述何者正確？', '["因乙就本件訴訟提起上訴，甲雖已逾上訴期間，仍得於第二審程序，對丙之請求部分提起附帶上訴", "甲於第二審程序，如另發現乙於系爭土地上無權興建地上物一棟，亦得提起附帶上訴，請求乙拆除 該地上物", "因乙就本件訴訟提起上訴，甲雖已逾上訴期間，仍得於第二審程序，就第一審判決駁回甲對乙之不 當得利請求部分，提起附帶上訴", "甲如就第一審判決對乙請求敗訴部分提起附帶上訴後，乙之上訴始經以不合法而被駁回，甲所為附 帶上訴，得視為合法獨立之上訴，不因乙之上訴不合法而受影響"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:39+00:00", "source_pdf_sha1": "3d06ebd3dac6", "answer_pdf_sha1": "a08edc8cf0cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "301", "s": "0409", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00460', 'judicial-57f41407', 'judicial-57f41407-moex-112-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '關於第三審訴訟程序，下列敘述何者正確？', '["第三審法院行言詞辯論時，被上訴人無資力委任訴訟代理人者，得聲請第三審法院為之選任律師為 訴訟代理人", "當事人對於第二審判決上訴，未委任律師為其訴訟代理人者，第三審法院得不命補正，逕以其上訴 不合法而裁定駁回", "對於第二審判決提起上訴，上訴人應於提起上訴後20日內提出理由書；未提出者，法院應先定相 當期間命其補正，逾期未補正者，法院應以裁定駁回其上訴", "被上訴人應於上訴狀或上訴理由書送達後15日內提出答辯狀，未提出者，視為對上訴人之主張不 爭執"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:39+00:00", "source_pdf_sha1": "3d06ebd3dac6", "answer_pdf_sha1": "a08edc8cf0cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "301", "s": "0409", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00461', 'judicial-57f41407', 'judicial-57f41407-moex-112-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '關於訴訟能力，下列敘述何者正確？', '["當事人就有無訴訟能力發生爭執時，法院不得就此為中間裁判", "法院未發現當事人無訴訟能力而為判決時，該判決當然無效", "法院發現當事人無訴訟能力時，應停止訴訟程序，不得裁定駁回原告之訴", "當事人於訴訟中喪失訴訟能力，法院應停止訴訟程序，不得裁定駁回原告之訴"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:39+00:00", "source_pdf_sha1": "3d06ebd3dac6", "answer_pdf_sha1": "a08edc8cf0cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "301", "s": "0409", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00462', 'judicial-57f41407', 'judicial-57f41407-moex-112-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '關於提起第三人撤銷之訴，下列敘述何者正確？', '["應於判決確定後20日之不變期間內提起", "第三人撤銷之訴之理由知悉在前者，均自知悉時起算起訴之不變期間", "起訴狀宜添具確定終局判決之繕本或影本", "起訴狀應記載準備本案言詞辯論之事項"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:39+00:00", "source_pdf_sha1": "3d06ebd3dac6", "answer_pdf_sha1": "a08edc8cf0cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "301", "s": "0409", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL)
